module RefModule (
   equal, 
   in
   ) ;
   input [16:0] in;
   output       equal;
   wire [15:0]  obf_inxor;
   wire [7:0]   nor1;
   wire [1:0]   nand2;
   assign obf_inxor[0] = in[15] ^ in[14];
   assign obf_inxor[1] = in[14] ^ in[13];
   assign obf_inxor[2] = in[13] ^ in[12];
   assign obf_inxor[3] = in[12] ^ in[11];
   assign obf_inxor[4] = in[11] ^ in[10];
   assign obf_inxor[5] = in[10] ^ in[9];
   assign obf_inxor[6] = in[9] ^ in[8];
   assign obf_inxor[7] = in[8] ^ in[7];
   assign obf_inxor[8] = in[7] ^ in[6];
   assign obf_inxor[9] = in[6] ^ in[5];
   assign obf_inxor[10] = in[5] ^ in[4];
   assign obf_inxor[11] = in[4] ^ in[3];
   assign obf_inxor[12] = in[3] ^ in[2];
   assign obf_inxor[13] = in[2] ^ in[1];
   assign obf_inxor[14] = in[1] ^ in[0];
   assign obf_inxor[15] = in[16] ^ in[15];
   assign nor1[0] = ~(obf_inxor[15] | obf_inxor[14]);
   assign       nor1[1] = ~(obf_inxor[1] | obf_inxor[0]);
   assign       nor1[2] = ~(obf_inxor[3] | obf_inxor[2]);
   assign       nor1[3] = ~(obf_inxor[5] | obf_inxor[4]);
   assign       nor1[4] = ~(obf_inxor[7] | obf_inxor[6]);
   assign       nor1[5] = ~(obf_inxor[9] | obf_inxor[8]);
   assign       nor1[6] = ~(obf_inxor[11] | obf_inxor[10]);
   assign       nor1[7] = ~(obf_inxor[13] | obf_inxor[12]);
   assign       nand2[0] = ~(nor1[1] & nor1[2] & nor1[3] & nor1[4]);
   assign       nand2[1] = ~(nor1[5] & nor1[6] & nor1[7] & nor1[0]);
   assign       equal = ~(nand2[1] | nand2[0]);
endmodule
